Rules.InvariantScript:
// add selected material items to the job
ForAll(
    colAddMaterialItems,
    With(
        {
            varType: "colCdsJobMaterialItems",
            varRecordRef: GUID()
        },
        Patch(
            colCdsJobMaterialItems,
            Defaults(colCdsJobMaterialItems),
            {
                appJobIDText: gblRecordJobCurrent.appJobIDText,
                Job: LookUp(
                    colCdsJobs,
                    appJobIDText = gblRecordJobCurrent.appJobIDText
                ),
                'Job Material Item': varRecordRef,
                'Market Material Item': LookUp(
                    colCdsMarketMaterialItems,
                    'Market Material Item' = colAddMaterialItems[@'Market Material Item']
                ),
                Name: colAddMaterialItems[@Name],
                Quantity: Blank()
            }
        );
        // add labor items to the AUD records collection
        Collect(
            colAUDRecords,
            {
                Type: varType,
                RecordRef: varRecordRef,
                Job: gblRecordJobCurrent.Job,
                Operation: "A"
            }
        );
    )
);
// save local data
IfError( // This line of code is added to hide the errors
If(
    gblAppLoadOffline,
    SaveData(
        colAUDRecords,
        "localAUDRecords"
    );
    SaveData(
        colCdsJobMaterialItems,
        "localCdsJobMaterialItems"
    );
)
,Blank())  // This line of code is added to hide the errors
;
// navigate back to materials screen
Reset(gal_MaterialAddItems__Filter);
Navigate('Materials Screen');
